SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_mem_m_share_mem ON sc_mem_m_share_mem CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_mem_m_share_mem() RETURNS trigger AS $BODY$
declare
  LI_COUNT integer;
BEGIN
    
  if coalesce(NEW.membership_no::text, '') = '' or NEW.membership_no = ' ' then
    CALL spa_dberror('กรุณากำหนดเลขทะเบียนสมาชิก');
  end if;

  if coalesce(NEW.RECRIEVE_SHARE::text, '') = '' then
    NEW.RECRIEVE_SHARE := 0;
  end  if;

  if coalesce(NEW.SHARE_AMOUNT::text, '') = '' then
    NEW.SHARE_AMOUNT := 0;
  end if;

  if coalesce(NEW.PERIOD_RECRIEVE::text, '') = '' then
    NEW.PERIOD_RECRIEVE := 0;
  end if;

  if coalesce(NEW.DROP_STATUS::text, '') = '' then
    NEW.DROP_STATUS := '0';
  end if;

  if coalesce(NEW.SHARE_STOCK::text, '') = '' then
    NEW.SHARE_STOCK := 0;
  end if;

  if coalesce(NEW.PENDING_AMT::text, '') = '' then
    NEW.PENDING_AMT := 0;
  end if;

  if coalesce(NEW.BEGIN_BALANCE::text, '') = '' then
    NEW.BEGIN_BALANCE := 0;
  end if;

  if coalesce(trim(both NEW.KEEPING_STATUS)::text, '') = '' then
    NEW.KEEPING_STATUS := '0';
  end if;

  if coalesce(NEW.share_amount_arrear::text, '') = '' then
    NEW.share_amount_arrear :=0;
  end if;

  if coalesce(NEW.pending_arrear::text, '') = '' then
    NEW.pending_arrear :=0;
  end if;

--  if :New.PERIOD_COMPOMISE is null then
--    :new.PERIOD_COMPOMISE := 0 ;
--  end if;
  -- เวลาที่แก้ไขล่าสุด(บังคับ)
  NEW.LAST_ACCESS_TIME := TO_CHAR(statement_timestamp(),'YYYY-MM-DD HH24:MI:SS.MS');

  IF NEW.share_qty = 0 or coalesce(NEW.share_qty::text, '') = '' THEN
    NEW.share_qty  := (NEW.SHARE_STOCK/pka_shr.fp_unitprice);
  END IF;

RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_mem_m_share_mem() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_mem_m_share_mem
	BEFORE INSERT OR UPDATE ON sc_mem_m_share_mem FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_mem_m_share_mem();

